module div_16bit
(
    input [15:0] A,
    input [7:0] B,
    output reg [15:0] result,
    output reg [15:0] odd
);
    reg [15:0] dividend;
    reg [7:0] divisor;
    reg [15:0] remainder;
    reg [15:0] quotient;
    integer i;

    always @(A or B) begin
        dividend <= A;
        divisor <= B;
    end

    always @(dividend or divisor) begin
        result <= 0;
        odd <= 0;
        remainder <= dividend;

        for (i = 0; i < 16; i = i + 1) begin
            if (remainder[15:8] >= divisor) begin
                remainder[15:8] = remainder[15:8] - divisor;
                remainder = {remainder[14:0], 1'b1};
            end
            else begin
                remainder = {remainder[14:0], 1'b0};
            end
        end

        result <= remainder[15:0];
        odd <= remainder[15:0];
    end
endmodule
